import React, { useState, useEffect, useRef } from 'react';
import './CircularGallery.css';

export default function CircularGallery({ items }) {
  const [rotation, setRotation] = useState(0);
  const [target, setTarget] = useState(0);
  const [hovered, setHovered] = useState(null);
  const rafRef = useRef(null);
  const dragging = useRef(false);
  const lastX = useRef(0);

  const count = items.length;
  const angleStep = 360 / count;
  const radius = 500;

  useEffect(() => {
    const tick = () => {
      setRotation(prev => {
        const d = target - prev;
        return Math.abs(d) < 0.01 ? target : prev + d * 0.07;
      });
      rafRef.current = requestAnimationFrame(tick);
    };
    rafRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(rafRef.current);
  }, [target]);

  const rotate = (dir) => setTarget(p => p + dir * angleStep);

  const onMouseDown = (e) => { dragging.current = true; lastX.current = e.clientX; };
  const onMouseMove = (e) => {
    if (!dragging.current) return;
    setTarget(p => p - (e.clientX - lastX.current) * 0.5);
    lastX.current = e.clientX;
  };
  const onMouseUp = () => { dragging.current = false; };

  const onTouchStart = (e) => { dragging.current = true; lastX.current = e.touches[0].clientX; };
  const onTouchMove = (e) => {
    if (!dragging.current) return;
    setTarget(p => p - (e.touches[0].clientX - lastX.current) * 0.5);
    lastX.current = e.touches[0].clientX;
  };

  return (
    <div className="cg-root">
      <button className="cg-arrow" onClick={() => rotate(1)}>‹</button>

      <div
        className="cg-scene"
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUp}
        onMouseLeave={onMouseUp}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onMouseUp}
      >
        <div
          className="cg-ring"
          style={{ transform: `rotateY(${rotation}deg)` }}
        >
          {items.map((item, i) => (
            <div
              key={i}
              className="cg-card"
              style={{
                transform: `rotateY(${i * angleStep}deg) translateZ(${radius}px)`,
              }}
              onMouseEnter={() => setHovered(i)}
              onMouseLeave={() => setHovered(null)}
            >
              <img src={item.image} alt={item.org} />
              <div className={`cg-overlay ${hovered === i ? 'visible' : ''}`}>
                <div className="cg-org">{item.org}</div>
                <div className="cg-divider" />
                <div className="cg-roles">
                  {item.roles.map((r) => <span key={r}>{r}</span>)}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <button className="cg-arrow" onClick={() => rotate(-1)}>›</button>
    </div>
  );
}
